import React, { useState, useEffect, useCallback } from "react";
import Header from "../../components/header/Header";
import GithubRepoCard from "../../components/githubRepoCard/GithubRepoCard";
import TopButton from "../../components/topButton/TopButton";
import { Fade } from "react-reveal";
import { seo } from "../../portfolio.js";
import "./Projects.css";
import { fetchWithApiKey } from "./ProjectManager.js";
import { ShimmerThumbnail } from "react-shimmer-effects";
import { Helmet } from "react-helmet";

export default function Projects({ theme }) {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [activeTag, setActiveTag] = useState(null);
  const [activeCategory, setActiveCategory] = useState(null);

  // Read ?prioritize=Category from URL to reorder projects
  const prioritizeCategory = new URLSearchParams(window.location.search).get(
    "prioritize",
  );

  const loadProjects = useCallback(async () => {
    setLoading(true);
    setError(false);
    try {
      const data = await fetchWithApiKey();
      if (!data || data.length === 0) {
        setProjects([]);
      } else {
        setProjects(data);
      }
    } catch {
      setError(true);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadProjects();
  }, [loadProjects]);

  const handleTagClick = (tag) => {
    setActiveTag((prev) => (prev === tag ? null : tag));
    setSearchQuery("");
    setActiveCategory(null);
  };

  const handleCategoryClick = (cat) => {
    setActiveCategory((prev) => (prev === cat ? null : cat));
    setActiveTag(null);
    setSearchQuery("");
  };

  const categories = React.useMemo(() => {
    const seen = new Set();
    return projects
      .map((p) => p.project_category)
      .filter((c) => c && !seen.has(c) && seen.add(c));
  }, [projects]);

  // Reorder: prioritized category first, then the rest (both keep original sequence)
  const sortedProjects = React.useMemo(() => {
    if (!prioritizeCategory) return projects;
    const cat = prioritizeCategory.toLowerCase();
    const prioritized = projects.filter(
      (p) => p.project_category?.toLowerCase() === cat,
    );
    const rest = projects.filter(
      (p) => p.project_category?.toLowerCase() !== cat,
    );
    return [...prioritized, ...rest];
  }, [projects, prioritizeCategory]);

  const filteredProjects = sortedProjects.filter((p) => {
    if (activeTag) {
      return p.project_tags?.includes(activeTag);
    }
    if (activeCategory) {
      return p.project_category === activeCategory;
    }
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      return (
        p.project_name?.toLowerCase().includes(q) ||
        p.project_description?.toLowerCase().includes(q) ||
        p.project_tags?.some((t) => t.toLowerCase().includes(q))
      );
    }
    return true;
  });

  return (
    <div className="projects-main">
      <Helmet>
        <title>{seo.title}</title>
        <meta name="description" content={seo.description} />
        <meta property="og:title" content={seo.og.title} />
        <meta property="og:type" content={seo.og.type} />
        <meta property="og:url" content={seo.og.url} />
      </Helmet>

      <Header theme={theme} />

      {!prioritizeCategory && (
        <div className="projects-search-bar-div">
          <div className="projects-search-bar-wrapper">
            <svg
              className="projects-search-icon"
              xmlns="http://www.w3.org/2000/svg"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
              aria-hidden="true"
            >
              <circle cx="11" cy="11" r="8" />
              <line x1="21" y1="21" x2="16.65" y2="16.65" />
            </svg>
            <input
              type="search"
              className="projects-search-bar"
              placeholder="Search projects by name or tag…"
              value={searchQuery}
              onChange={(e) => {
                setSearchQuery(e.target.value);
                setActiveTag(null);
              }}
              aria-label="Search projects"
              style={{
                borderColor: theme.imageHighlight,
                color: theme.text,
                backgroundColor: theme.whiteBG,
              }}
            />
          </div>
          {activeTag && (
            <div className="projects-active-filter">
              Filtering by tag:{" "}
              <span
                className="chip active-tag-chip"
                style={{ backgroundColor: theme.imageHighlight, color: "#fff" }}
              >
                {activeTag}
              </span>
              <button
                className="clear-filter-btn"
                onClick={() => setActiveTag(null)}
                aria-label="Clear tag filter"
                style={{ color: theme.imageHighlight }}
              >
                × Clear
              </button>
            </div>
          )}
        </div>
      )}

      {!prioritizeCategory && categories.length > 1 && (
        <div className="projects-category-chips">
          {categories.map((cat) => (
            <button
              key={cat}
              className={`category-chip${
                activeCategory === cat ? " category-chip-active" : ""
              }`}
              onClick={() => handleCategoryClick(cat)}
              aria-pressed={activeCategory === cat}
              style={
                activeCategory === cat
                  ? {
                      backgroundColor: theme.imageHighlight,
                      color: "#fff",
                      borderColor: theme.imageHighlight,
                    }
                  : {
                      borderColor: theme.imageHighlight,
                      color: theme.imageHighlight,
                    }
              }
            >
              {cat}
            </button>
          ))}
        </div>
      )}

      {loading ? (
        <div className="shimmer-grid">
          {Array.from({ length: 8 }).map((_, i) => (
            <ShimmerThumbnail key={i} rounded className="shimmer" />
          ))}
        </div>
      ) : error ? (
        <div className="projects-error-state">
          <p style={{ color: theme.secondaryText }}>
            Failed to load projects. Please check your connection and try again.
          </p>
          <button
            className="retry-btn"
            onClick={loadProjects}
            style={{
              backgroundColor: theme.imageHighlight,
              color: "#fff",
            }}
          >
            Retry
          </button>
        </div>
      ) : filteredProjects.length === 0 ? (
        <div className="projects-empty-state">
          <svg
            width="80"
            height="80"
            viewBox="0 0 24 24"
            fill="none"
            stroke={theme.secondaryText}
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
            aria-hidden="true"
          >
            <circle cx="11" cy="11" r="8" />
            <line x1="21" y1="21" x2="16.65" y2="16.65" />
          </svg>
          <p style={{ color: theme.secondaryText }}>
            {projects.length === 0
              ? "No projects yet. Check back soon!"
              : "No projects match your search."}
          </p>
          {(searchQuery || activeTag || activeCategory) && (
            <button
              className="retry-btn"
              onClick={() => {
                setSearchQuery("");
                setActiveTag(null);
                setActiveCategory(null);
              }}
              style={{ backgroundColor: theme.imageHighlight, color: "#fff" }}
            >
              Clear filter
            </button>
          )}
        </div>
      ) : (
        <div className="repo-cards-div-main">
          {filteredProjects.map((repo, index) => (
            <GithubRepoCard
              key={repo.id || index}
              repo={repo}
              theme={theme}
              onTagClick={handleTagClick}
              activeTag={activeTag}
            />
          ))}
        </div>
      )}

      <TopButton theme={theme} />
    </div>
  );
}
